import { TILE_SIZE, WORLD_WIDTH, WORLD_HEIGHT, TILE_TYPES, CANVAS_WIDTH, CANVAS_HEIGHT } from './globals.js';

// Generate terrain using perlin noise
export function generateWorld(p) {
  const world = Array(WORLD_WIDTH).fill().map(() => Array(WORLD_HEIGHT).fill(TILE_TYPES.AIR));

  // Generate terrain height using perlin noise
  const groundHeights = [];
  for (let x = 0; x < WORLD_WIDTH; x++) {
    const height = Math.floor(p.noise(x * 0.05) * 10) + 30;
    groundHeights.push(height);
  }

  // Fill terrain
  for (let x = 0; x < WORLD_WIDTH; x++) {
    const groundHeight = groundHeights[x];

    // Add grass at the top
    world[x][groundHeight] = TILE_TYPES.GRASS;

    // Add dirt below grass
    for (let y = groundHeight + 1; y < groundHeight + 5; y++) {
      if (y < WORLD_HEIGHT) {
        world[x][y] = TILE_TYPES.DIRT;
      }
    }

    // Add stone below dirt
    for (let y = groundHeight + 5; y < WORLD_HEIGHT; y++) {
      world[x][y] = TILE_TYPES.STONE;
    }
  }

  // Add ores
  addOres(world, p, TILE_TYPES.IRON_ORE, 150, 40);
  addOres(world, p, TILE_TYPES.GOLD_ORE, 80, 50);

  // Add trees
  addTrees(world, p, groundHeights);

  return world;
}

// Add ore veins to the world
function addOres(world, p, oreType, count, minDepth) {
  for (let i = 0; i < count; i++) {
    const x = Math.floor(p.random(WORLD_WIDTH));
    const y = Math.floor(p.random(minDepth, WORLD_HEIGHT));

    if (world[x][y] === TILE_TYPES.STONE) {
      const veinSize = Math.floor(p.random(3, 6));

      for (let vx = -veinSize; vx <= veinSize; vx++) {
        for (let vy = -veinSize; vy <= veinSize; vy++) {
          const nx = x + vx;
          const ny = y + vy;

          if (nx >= 0 && nx < WORLD_WIDTH && ny >= 0 && ny < WORLD_HEIGHT) {
            const dist = Math.sqrt(vx * vx + vy * vy);

            if (dist <= veinSize * 0.7 && world[nx][ny] === TILE_TYPES.STONE && p.random() > 0.5) {
              world[nx][ny] = oreType;
            }
          }
        }
      }
    }
  }
}

// Add trees to the world
function addTrees(world, p, groundHeights) {
  for (let x = 5; x < WORLD_WIDTH - 5; x += Math.floor(p.random(5, 15))) {
    const groundY = groundHeights[x];

    if (groundY < WORLD_HEIGHT - 10 && world[x][groundY] === TILE_TYPES.GRASS) {
      const treeHeight = Math.floor(p.random(4, 8));

      // Tree trunk
      for (let y = groundY - 1; y > groundY - treeHeight; y--) {
        if (y >= 0) {
          world[x][y] = TILE_TYPES.WOOD;
        }
      }
    }
  }
}

// Draw the visible portion of the world
export function drawWorld(p, world, cameraX, cameraY) {
  const startX = Math.floor(cameraX / TILE_SIZE);
  const startY = Math.floor(cameraY / TILE_SIZE);
  const endX = startX + Math.ceil(CANVAS_WIDTH / TILE_SIZE) + 1;
  const endY = startY + Math.ceil(CANVAS_HEIGHT / TILE_SIZE) + 1;

  for (let x = startX; x < endX; x++) {
    for (let y = startY; y < endY; y++) {
      if (x >= 0 && x < WORLD_WIDTH && y >= 0 && y < WORLD_HEIGHT) {
        const tileType = world[x][y];
        const screenX = x * TILE_SIZE - cameraX;
        const screenY = y * TILE_SIZE - cameraY;

        if (tileType !== TILE_TYPES.AIR) {
          drawTile(p, tileType, screenX, screenY);
        }
      }
    }
  }
}

// Draw a single tile
function drawTile(p, tileType, x, y) {
  switch(tileType) {
    case TILE_TYPES.GRASS:
      p.fill(34, 139, 34);
      p.rect(x, y, TILE_SIZE, TILE_SIZE);
      p.fill(82, 46, 23);
      p.rect(x, y + TILE_SIZE/2, TILE_SIZE, TILE_SIZE/2);
      break;
    case TILE_TYPES.DIRT:
      p.fill(82, 46, 23);
      p.rect(x, y, TILE_SIZE, TILE_SIZE);
      break;
    case TILE_TYPES.STONE:
      p.fill(128, 128, 128);
      p.rect(x, y, TILE_SIZE, TILE_SIZE);
      break;
    case TILE_TYPES.WOOD:
      p.fill(139, 69, 19);
      p.rect(x, y, TILE_SIZE, TILE_SIZE);
      p.fill(101, 67, 33);
      p.rect(x + 5, y, 2, TILE_SIZE);
      p.rect(x + 13, y, 2, TILE_SIZE);
      break;
    case TILE_TYPES.IRON_ORE:
      p.fill(128, 128, 128);
      p.rect(x, y, TILE_SIZE, TILE_SIZE);
      p.fill(170, 169, 173);
      p.ellipse(x + 5, y + 7, 6, 6);
      p.ellipse(x + 12, y + 13, 8, 8);
      p.ellipse(x + 15, y + 5, 5, 5);
      break;
    case TILE_TYPES.GOLD_ORE:
      p.fill(128, 128, 128);
      p.rect(x, y, TILE_SIZE, TILE_SIZE);
      p.fill(255, 215, 0);
      p.ellipse(x + 7, y + 5, 6, 6);
      p.ellipse(x + 14, y + 11, 8, 8);
      p.ellipse(x + 5, y + 15, 5, 5);
      break;
    case TILE_TYPES.WOODEN_PLATFORM:
      p.fill(139, 69, 19);
      p.rect(x, y + TILE_SIZE/2 - 2, TILE_SIZE, 4);
      break;
    case TILE_TYPES.WOODEN_WALL:
      p.fill(139, 69, 19);
      p.rect(x, y, TILE_SIZE, TILE_SIZE);
      p.fill(101, 67, 33);
      p.rect(x, y, TILE_SIZE, 2);
      p.rect(x, y + TILE_SIZE/2, TILE_SIZE, 2);
      p.rect(x, y + TILE_SIZE - 2, TILE_SIZE, 2);
      break;
    case TILE_TYPES.STONE_WALL:
      p.fill(128, 128, 128);
      p.rect(x, y, TILE_SIZE, TILE_SIZE);
      p.fill(100, 100, 100);
      p.rect(x, y, TILE_SIZE, 2);
      p.rect(x, y + TILE_SIZE/2, TILE_SIZE, 2);
      p.rect(x, y + TILE_SIZE - 2, TILE_SIZE, 2);
      p.rect(x, y, 2, TILE_SIZE);
      p.rect(x + TILE_SIZE/2, y, 2, TILE_SIZE);
      p.rect(x + TILE_SIZE - 2, y, 2, TILE_SIZE);
      break;
  }
}

// Check if a tile is solid (can't pass through)
export function isSolidTile(tileType) {
  return tileType !== TILE_TYPES.AIR && tileType !== TILE_TYPES.WOODEN_PLATFORM;
}

// Check if a tile is a platform (can stand on but can drop through)
export function isPlatform(tileType) {
  return tileType === TILE_TYPES.WOODEN_PLATFORM;
}

// Get tile at world coordinates
export function getTileAt(world, x, y) {
  const tileX = Math.floor(x / TILE_SIZE);
  const tileY = Math.floor(y / TILE_SIZE);

  if (tileX >= 0 && tileX < WORLD_WIDTH && tileY >= 0 && tileY < WORLD_HEIGHT) {
    return world[tileX][tileY];
  }

  return TILE_TYPES.AIR;
}

// Set tile at world coordinates
export function setTileAt(world, x, y, tileType) {
  const tileX = Math.floor(x / TILE_SIZE);
  const tileY = Math.floor(y / TILE_SIZE);

  if (tileX >= 0 && tileX < WORLD_WIDTH && tileY >= 0 && tileY < WORLD_HEIGHT) {
    world[tileX][tileY] = tileType;
    return true;
  }

  return false;
}

// Convert tile type to item type when mining
export function tileToItem(tileType) {
  switch(tileType) {
    case TILE_TYPES.WOOD:
      return 'wood';
    case TILE_TYPES.STONE:
    case TILE_TYPES.STONE_WALL:
      return 'stone';
    case TILE_TYPES.IRON_ORE:
      return 'iron';
    case TILE_TYPES.GOLD_ORE:
      return 'gold';
    case TILE_TYPES.WOODEN_PLATFORM:
    case TILE_TYPES.WOODEN_WALL:
      return 'wood';
    default:
      return null;
  }
}

// Convert item type to tile type when placing
export function itemToTile(itemType) {
  switch(itemType) {
    case 'wooden_platform':
      return TILE_TYPES.WOODEN_PLATFORM;
    case 'wooden_wall':
      return TILE_TYPES.WOODEN_WALL;
    case 'stone_wall':
      return TILE_TYPES.STONE_WALL;
    default:
      return null;
  }
}
</code>

<code filename="player.js">
import { TILE_SIZE, GRAVITY, JUMP_FORCE, MOVE_SPEED, TOOL_TYPES, ITEM_TYPES } from './globals.js';
import { isSolidTile, isPlatform, getTileAt, setTileAt, tileToItem, itemToTile } from './world.js';

export class Player {
  constructor(x, y) {
    this.x = x;
    this.y = y;
    this.width = 16;
    this.height = 32;
    this.velocityX = 0;
    this.velocityY = 0;
    this.isJumping = false;
    this.isGrounded = false;
    this.facingRight = true;
    this.mining = false;
    this.miningCooldown = 0;
    this.attackCooldown = 0;
    this.hurtCooldown = 0;
    this.dropThroughPlatform = false;
  }

  update(p, world, entities, inventory, selectedTool, selectedBlock) {
    this.applyPhysics(world);
    this.handleMining(p, world, inventory, selectedTool);
    this.handleAttack(p, entities);
    this.handleBlockPlacement(p, world, inventory, selectedBlock);

    if (this.miningCooldown > 0) this.miningCooldown--;
    if (this.attackCooldown > 0) this.attackCooldown--;
    if (this.hurtCooldown > 0) this.hurtCooldown--;

    // Reset mining flag
    this.mining = false;
  }

  applyPhysics(world) {
    // Apply gravity
    this.velocityY += GRAVITY;

    // Check if player is on ground
    this.isGrounded = false;

    // Bottom collision
    const bottomY = this.y + this.height;
    const leftX = this.x;
    const rightX = this.x + this.width;

    for (let testX = leftX; testX <= rightX; testX += this.width) {
      const tileType = getTileAt(world, testX, bottomY + 1);

      if (isSolidTile(tileType) || (isPlatform(tileType) && !this.dropThroughPlatform && this.velocityY >= 0)) {
        this.isGrounded = true;
        this.velocityY = 0;
        this.y = Math.floor((bottomY + 1) / TILE_SIZE) * TILE_SIZE - this.height;
        break;
      }
    }

    // Apply horizontal movement
    this.x += this.velocityX;

    // Left collision
    if (this.velocityX < 0) {
      const leftX = this.x;
      const topY = this.y;
      const bottomY = this.y + this.height;

      for (let testY = topY; testY < bottomY; testY += TILE_SIZE) {
        if (isSolidTile(getTileAt(world, leftX, testY))) {
          this.x = Math.floor(leftX / TILE_SIZE + 1) * TILE_SIZE;
          this.velocityX = 0;
          break;
        }
      }
    }

    // Right collision
    if (this.velocityX > 0) {
      const rightX = this.x + this.width;
      const topY = this.y;
      const bottomY = this.y + this.height;

      for (let testY = topY; testY < bottomY; testY += TILE_SIZE) {
        if (isSolidTile(getTileAt(world, rightX, testY))) {
          this.x = Math.floor(rightX / TILE_SIZE) * TILE_SIZE - this.width;
          this.velocityX = 0;
          break;
        }
      }
    }

    // Apply vertical movement
    this.y += this.velocityY;

    // Top collision
    if (this.velocityY < 0) {
      const topY = this.y;
      const leftX = this.x;
      const rightX = this.x + this.width;

      for (let testX = leftX; testX <= rightX; testX += this.width) {
        if (isSolidTile(getTileAt(world, testX, topY))) {
          this.y = Math.floor(topY / TILE_SIZE + 1) * TILE_SIZE;
          this.velocityY = 0;
          break;
        }
      }
    }

    // Bottom collision again after movement
    if (this.velocityY > 0) {
      const bottomY = this.y + this.height;
      const leftX = this.x;
      const rightX = this.x + this.width;

      for (let testX = leftX; testX <= rightX; testX += this.width) {
        const tileType = getTileAt(world, testX, bottomY);

        if (isSolidTile(tileType) || (isPlatform(tileType) && !this.dropThroughPlatform)) {
          this.isGrounded = true;
          this.velocityY = 0;
          this.y = Math.floor(bottomY / TILE_SIZE) * TILE_SIZE - this.height;
          break;
        }
      }
    }

    // Limit velocity
    this.velocityY = Math.min(this.velocityY, 15);

    // Apply friction
    this.velocityX *= 0.8;
    if (Math.abs(this.velocityX) < 0.1) this.velocityX = 0;
  }

  jump() {
    if (this.isGrounded) {
      this.velocityY = -JUMP_FORCE;
      this.isJumping = true;
      this.isGrounded = false;
    }
  }

  moveLeft() {
    this.velocityX = -MOVE_SPEED;
    this.facingRight = false;
  }

  moveRight() {
    this.velocityX = MOVE_SPEED;
    this.facingRight = true;
  }

  duck(isDucking) {
    this.dropThroughPlatform = isDucking;
  }

  mine(p, world, inventory) {
    if (this.miningCooldown > 0) return;

    this.mining = true;
    this.miningCooldown = 15; // Mining cooldown

    // Mining distance
    const mineDistance = 40;
    const mineX = this.facingRight ? this.x + this.width + 5 : this.x - 25;
    const mineY = this.y + this.height / 2;

    // Get tile at mining position
    const tileType = getTileAt(world, mineX, mineY);

    if (tileType !== 0) { // Not air
      const itemType = tileToItem(tileType);

      if (itemType) {
        // Add to inventory
        if (!inventory[itemType]) {
          inventory[itemType] = 0;
        }
        inventory[itemType]++;

        // Remove tile
        setTileAt(world, mineX, mineY, 0);
      }
    }
  }

  handleMining(p, world, inventory, selectedTool) {
    if (p.keyIsDown(32)) { // SPACE
      if (selectedTool === TOOL_TYPES.PICKAXE || selectedTool === TOOL_TYPES.AXE) {
        this.mine(p, world, inventory);
      }
    }
  }

  handleAttack(p, entities) {
    if (p.keyIsDown(32) && this.attackCooldown === 0) { // SPACE
      const attackDistance = 40;
      const attackX = this.facingRight ? this.x + this.width : this.x - attackDistance;
      const attackWidth = attackDistance;

      // Check for enemy collisions
      for (let i = 0; i < entities.length; i++) {
        const entity = entities[i];

        if (entity.type && entity.type.includes('enemy')) {
          if (this.facingRight) {
            if (entity.x < attackX + attackWidth && entity.x + entity.width > attackX &&
                entity.y < this.y + this.height && entity.y + entity.height > this.y) {
              entity.takeDamage(10);
              this.attackCooldown = 20;
            }
          } else {
            if (entity.x < attackX + attackWidth && entity.x + entity.width > attackX &&
                entity.y < this.y + this.height && entity.y + entity.height > this.y) {
              entity.takeDamage(10);
              this.attackCooldown = 20;
            }
          }
        }
      }
    }
  }

  handleBlockPlacement(p, world, inventory, selectedBlock) {
    if (p.keyIsDown(16) && selectedBlock) { // SHIFT
      if (inventory[selectedBlock] && inventory[selectedBlock] > 0) {
        const placeX = this.facingRight ? this.x + this.width + 5 : this.x - 25;
        const placeY = this.y + this.height / 2;

        const tileType = getTileAt(world, placeX, placeY);

        if (tileType === 0) { // Only place in air
          const blockTile = itemToTile(selectedBlock);

          if (blockTile && setTileAt(world, placeX, placeY, blockTile)) {
            inventory[selectedBlock]--;
          }
        }
      }
    }
  }

  takeDamage(amount) {
    if (this.hurtCooldown === 0) {
      this.hurtCooldown = 30;
      return amount;
    }
    return 0;
  }

  draw(p, cameraX, cameraY) {
    const screenX = this.x - cameraX;
    const screenY = this.y - cameraY;

    // Draw player
    p.push();
    if (this.hurtCooldown > 0 && Math.floor(p.frameCount / 4) % 2 === 0) {
      p.tint(255, 0, 0, 200);
    }

    p.fill(255, 200, 150); // Skin color
    p.rect(screenX, screenY, this.width, this.height);

    // Draw eyes
    p.fill(0);
