    }

    // Draw body
    p.fill(50, 100, 200); // Shirt color
    p.rect(screenX, screenY + 12, this.width, this.height - 12);

    // Draw mining/attack animation
    if (this.mining || this.attackCooldown > 0) {
      p.fill(139, 69, 19);
      if (this.facingRight) {
        p.rect(screenX + this.width, screenY + 10, 20, 5);
      } else {
        p.rect(screenX - 20, screenY + 10, 20, 5);
      }
    }

    p.pop();
  }
}
