    gameState.bossSpawned = false;

    // Reset crafting
    showCrafting = true;

    // Reset testing variables
    gameState.lastActionTime = 0;
    gameState.actionHistory = [];
  }

  // Key pressed event
  p.keyPressed = function() {
    // Store key state
    keyStates[p.keyCode] = true;

    // Log input
    logInput("keyPressed", { key: p.key, keyCode: p.keyCode });

    // Handle game phase transitions
    if (p.keyCode === 13) { // ENTER
      if (gameState.gamePhase === "START") {
        gameState.gamePhase = "PLAYING";
        logGameInfo("PLAYING", {});
      }
    } else if (p.keyCode === 27) { // ESC
      if (gameState.gamePhase === "PLAYING") {
        gameState.gamePhase = "PAUSED";
        logGameInfo("PAUSED", {});
      } else if (gameState.gamePhase === "PAUSED") {
        gameState.gamePhase = "PLAYING";
        logGameInfo("PLAYING", {});
      }
    } else if (p.keyCode === 82) { // R
      if (gameState.gamePhase === "GAME_OVER_WIN" || gameState.gamePhase === "GAME_OVER_LOSE") {
        resetGame();
        gameState.gamePhase = "START";
        logGameInfo("START", {});
      }
    }

    // Handle tool switching
    if (p.keyCode === 90 && gameState.gamePhase === "PLAYING") { // Z
      // Cycle through tools and blocks
      if (gameState.selectedBlock) {
        // Cycle through placeable blocks
        const blocks = [
          ITEM_TYPES.WOODEN_PLATFORM,
          ITEM_TYPES.WOODEN_WALL,
          ITEM_TYPES.STONE_WALL,
          null
        ];

        let currentIndex = blocks.indexOf(gameState.selectedBlock);
        currentIndex = (currentIndex + 1) % blocks.length;

        gameState.selectedBlock = blocks[currentIndex];

        if (gameState.selectedBlock === null) {
          // Switch to tools if we've cycled through all blocks
          gameState.selectedTool = TOOL_TYPES.PICKAXE;
        }
      } else {
        // Cycle through tools
        if (gameState.selectedTool === TOOL_TYPES.PICKAXE) {
          gameState.selectedTool = TOOL_TYPES.AXE;
        } else if (gameState.selectedTool === TOOL_TYPES.AXE) {
          gameState.selectedTool = TOOL_TYPES.SWORD;
        } else if (gameState.selectedTool === TOOL_TYPES.SWORD) {
          // Switch to blocks if we have any
          if (gameState.inventory[ITEM_TYPES.WOODEN_PLATFORM] > 0) {
            gameState.selectedBlock = ITEM_TYPES.WOODEN_PLATFORM;
          } else if (gameState.inventory[ITEM_TYPES.WOODEN_WALL] > 0) {
            gameState.selectedBlock = ITEM_TYPES.WOODEN_WALL;
          } else if (gameState.inventory[ITEM_TYPES.STONE_WALL] > 0) {
            gameState.selectedBlock = ITEM_TYPES.STONE_WALL;
          } else {
            gameState.selectedTool = TOOL_TYPES.PICKAXE;
          }
        }
      }
    }

    return false; // Prevent default behavior
  };

  // Key released event
  p.keyReleased = function() {
    // Clear key state
    keyStates[p.keyCode] = false;

    // Log input
    logInput("keyReleased", { key: p.key, keyCode: p.keyCode });

    return false; // Prevent default behavior
  };

  // Log game information
  function logGameInfo(status, data) {
    p.logs.game_info.push({
      "game_status": status,
      "data": data,
      "framecount": p.frameCount,
      "timestamp": Date.now()
    });
  }

  // Log player information
  function logPlayerInfo() {
    p.logs.player_info.push({
      "screen_x": gameState.player.x - gameState.camera.x,
      "screen_y": gameState.player.y - gameState.camera.y,
      "game_x": gameState.player.x,
      "game_y": gameState.player.y,
      "framecount": p.frameCount,
      "timestamp": Date.now()
    });
  }

  // Log input information
  function logInput(inputType, data) {
    // Only log allowed keys
    const allowedKeys = [13, 27, 82, 37, 38, 39, 40, 32, 16, 90];

    if (allowedKeys.includes(data.keyCode)) {
      p.logs.inputs.push({
        "input_type": inputType,
        "data": data,
        "framecount": p.frameCount,
        "timestamp": Date.now()
      });
    }
  }
});

// Expose the game instance globally
window.gameInstance = gameInstance;
